<template>
  <div class="admin-panel" :style="cssVars">
    <div v-if="!supabase" class="setup-screen">
      <div class="setup-card">
        <div style="font-size:32px;margin-bottom:12px"><span v-if="content.iconSetup" v-html="getIconHtml('iconSetup')" class="icon-svg" style="width:32px;height:32px"></span><template v-else>⚙</template></div>
        <div style="font-size:18px;font-weight:700;margin-bottom:8px">Admin Panel</div>
        <div class="text-muted text-sm">Oczekiwanie na połączenie z Supabase</div>
      </div>
    </div>
    <template v-else>
      <div class="layout">
        <button class="hamburger-btn" @click="sidebarOpen=!sidebarOpen">☰</button>
        <div v-if="sidebarOpen" class="sidebar-overlay" @click="sidebarOpen=false"></div>
        <nav v-if="content.showSidebar!==false" class="sidebar" :class="{'sidebar-open':sidebarOpen}" :style="sidebarStyle">
          <div v-if="L('labelSidebarTitle')" class="sidebar-brand">
            <div class="sidebar-name">{{L('labelSidebarTitle')}}</div>
            <div v-if="L('labelSidebarSubtitle')" class="text-muted text-sm">{{L('labelSidebarSubtitle')}}</div>
          </div>
          <div class="sidebar-nav">
            <button v-for="n in navItems" :key="n.id" class="nav-btn" :class="{active:activePage===n.id}" @click="activePage=n.id">
              <span class="nav-icon"><span v-if="content[n.imgKey]" v-html="getIconHtml(n.imgKey)" class="nav-icon-svg" :style="{width:content.navIconSize||'18px',height:content.navIconSize||'18px'}"></span><template v-else>{{n.icon}}</template></span>{{n.label}}<span v-if="n.badge" class="nav-badge">{{n.badge}}</span>
            </button>
          </div>
        </nav>
        <main class="main-content">
          <div v-if="loading" class="loader"><div class="spinner"></div><div class="text-muted text-sm">Ładowanie...</div></div>

          <!-- DASHBOARD -->
          <div v-else-if="activePage==='dashboard'" class="page">
            <h1 class="page-title">{{L('labelDashboard')}}</h1>
            <div class="stats-row">
              <div v-for="s in dashCards" :key="s.id" class="stat-card">
                <div class="stat-accent" :style="{background:s.c}"></div>
                <div class="stat-value">{{s.v}}</div>
                <div class="stat-label text-muted text-sm">{{s.l}}</div>
              </div>
            </div>
            <div class="grid-2col">
              <div class="card"><div class="card-title">{{L('labelRolesDistribution')}}</div>
                <div v-for="r in (stats.roles_distribution||[])" :key="r.role" class="role-bar-row">
                  <span class="role-badge" :style="roleBadgeStyle(r.role)">{{r.role}}</span>
                  <div class="bar-track"><div class="bar-fill" :style="{width:((r.count/Math.max(stats.total_managers,1))*100)+'%'}"></div></div>
                  <span class="bar-count mono text-muted text-sm">{{r.count}}</span>
                </div>
              </div>
              <div class="card"><div class="card-title">{{L('labelDepartments')}}<span v-if="deptStats.length" class="text-muted text-sm" style="font-weight:400;margin-left:auto">{{L('labelDiffPeriod')}}</span></div>
                <div v-for="d in (deptStats.length?deptStats:stats.departments||[])" :key="d.id||d.name" class="dept-row"><span>{{d.name}}</span><span class="dept-stats-right"><span class="mono text-muted text-sm">{{d.current_count!=null?d.current_count:d.clients}}</span><span v-if="d.diff!=null" class="dept-diff mono text-sm" :class="diffClass(d.diff)">{{diffText(d.diff)}}</span></span></div>
              </div>
            </div>
            <div class="card margin-t-md chart-card">
              <div class="chart-header"><div class="card-title" style="margin-bottom:0">{{L('labelClientsChart')}}</div>
                <div class="chart-date-range"><input type="date" class="input-field input-date" v-model="chartFrom" @change="loadChart"/><span class="text-muted text-sm">—</span><input type="date" class="input-field input-date" v-model="chartTo" @change="loadChart"/></div>
              </div>
              <div v-if="chartLoading" class="chart-loading"><div class="spinner"></div></div>
              <div v-else-if="!chartData.length" class="empty-state text-sm">Brak danych za wybrany okres</div>
              <div v-else class="chart-wrapper">
                <div class="chart-container" ref="chartContainer" @mouseleave="chartHover=null">
                  <svg class="chart-svg" viewBox="0 0 640 200" preserveAspectRatio="none">
                    <defs><linearGradient id="chartGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" :stop-color="cssVars['--chart-line']||'#6366f1'" stop-opacity="0.3"/><stop offset="100%" :stop-color="cssVars['--chart-line']||'#6366f1'" stop-opacity="0.02"/></linearGradient></defs>
                    <line v-for="yl in chartYLabels()" :key="'g'+yl.v" x1="40" :y1="yl.y" x2="640" :y2="yl.y" stroke="var(--chart-grid)" stroke-width="1" stroke-dasharray="4,4"/>
                    <text v-for="yl in chartYLabels()" :key="'t'+yl.v" x="36" :y="yl.y+3" text-anchor="end" fill="var(--chart-label)" font-size="9" font-family="monospace">{{yl.v}}</text>
                    <g transform="translate(40,0)">
                      <path :d="chartAreaPath()" fill="url(#chartGrad)"/>
                      <path :d="chartPath()" fill="none" stroke="var(--chart-line)" :stroke-width="cssVars['--chart-line-w']||'2px'" stroke-linecap="round" stroke-linejoin="round"/>
                    </g>
                    <g v-if="chartData.length<=31" transform="translate(40,0)">
                      <text v-for="(p,i) in chartXLabels()" :key="'xl'+i" :x="p.x" y="196" text-anchor="middle" fill="var(--chart-label)" font-size="8" font-family="monospace">{{p.label}}</text>
                    </g>
                  </svg>
                  <div v-for="(p,i) in chartPoints()" :key="'dot'+i" class="chart-dot-html" :class="{'chart-dot-dense':chartData.length>15}" :style="{left:((40+p.x)/640*100)+'%',top:(p.y/200*100)+'%',width:(parseFloat(content.chartDotSize)||4)*2+'px',height:(parseFloat(content.chartDotSize)||4)*2+'px'}" @mouseenter="showChartTip($event,p)" @mouseleave="chartHover=null"></div>
                  <div v-if="chartHover" class="chart-tooltip" :style="chartTipStyle"><strong>{{chartHover.count}}</strong><span class="text-muted text-sm" style="margin-left:6px">{{chartHover.day}}</span></div>
                </div>
              </div>
            </div>
          </div>

          <!-- USERS -->
          <div v-else-if="activePage==='users'" class="page">
            <div class="page-title-row"><h1 class="page-title">{{L('labelUsers')}}</h1><button class="btn-ghost" @click="exportCSV('users')">{{L('labelBtnExport')}}</button></div>
            <div class="toolbar">
              <div class="search-wrapper" style="position:relative;flex:1">
                <input class="input-field" v-model="searchQuery" :placeholder="L('labelSearch')" @focus="searchSuggestionsOpen=true" @blur="setTimeout(()=>searchSuggestionsOpen=false,200)" autocomplete="off"/>
                <div v-if="searchSuggestionsOpen&&searchSuggestions.length&&searchQuery.length>=2" class="search-suggestions">
                  <div v-for="s in searchSuggestions" :key="s.id" class="search-suggestion-item" @mousedown.prevent="selectSuggestion(s)"><strong>{{s.full_name}}</strong> <span class="text-muted text-sm">{{s.email}}</span><span v-if="s.oddzial" class="text-muted text-sm"> — {{s.oddzial}}</span></div>
                </div>
              </div>
              <select class="select-field" v-model="filterRole"><option value="">{{L('labelAllRoles')}}</option><option v-for="r in allRoles" :key="r" :value="r">{{r}}</option></select>
              <select class="select-field" v-model="filterStatus"><option value="">{{L('labelAllStatuses')}}</option><option value="active">{{L('labelStatusActive')}}</option><option value="inactive">{{L('labelStatusInactive')}}</option><option value="terminated">{{L('labelStatusTerminated')}}</option><option value="vacation">{{L('labelStatusVacation')}}</option></select>
              <select class="select-field" v-model="filterDept"><option value="">{{L('labelAllDepts')}}</option><option v-for="o in allOdz" :key="o.id" :value="o.name">{{o.name}}</option></select>
            </div>
            <div v-if="selectedUserIds.length" class="bulk-toolbar">
              <span class="text-sm">{{L('labelBulkSelected')}}: <strong>{{selectedUserIds.length}}</strong></span>
              <button class="btn-secondary" @click="openModal('bulkRole')">{{L('labelBulkAddRole')}}</button>
              <button class="btn-secondary" @click="openModal('bulkDept')">{{L('labelBulkAddDept')}}</button>
              <button class="btn-ghost" @click="selectedUserIds=[]">{{L('labelClearAll')}}</button>
            </div>
            <div class="card no-pad">
              <div class="table-header">
                <span class="col-check"><div class="checkbox" :class="{active:selectedUserIds.length===paginatedUsers.length&&paginatedUsers.length>0}" @click="toggleBulkAll"><span v-if="selectedUserIds.length===paginatedUsers.length&&paginatedUsers.length>0">✓</span></div></span><span class="col-user sortable-header" @click="toggleSort('full_name')">{{L('labelColUser')}} <span class="sort-icon">{{sortIcon('full_name')}}</span></span><span class="col-roles sortable-header" @click="toggleSort('roles')">{{L('labelColRoles')}} <span class="sort-icon">{{sortIcon('roles')}}</span></span><span class="col-depts sortable-header" @click="toggleSort('depts')">{{L('labelColDepts')}} <span class="sort-icon">{{sortIcon('depts')}}</span></span><span class="col-clients sortable-header" @click="toggleSort('visible_clients_count')">{{L('labelColClients')}} <span class="sort-icon">{{sortIcon('visible_clients_count')}}</span></span><span class="col-status sortable-header" @click="toggleSort('status')">{{L('labelColStatus')}} <span class="sort-icon">{{sortIcon('status')}}</span></span>
              </div>
              <div v-for="u in paginatedUsers" :key="u.id" class="table-row" :class="{selected:selectedUser&&selectedUser.id===u.id||selectedUserIds.includes(u.id)}" @click="openDetail(u)">
                <div class="col-check" @click.stop="toggleBulkUser(u.id)"><div class="checkbox" :class="{active:selectedUserIds.includes(u.id)}"><span v-if="selectedUserIds.includes(u.id)">✓</span></div></div>
                <div class="col-user">
                  <div class="user-name">{{u.full_name}}<span v-if="u.is_super_admin" class="badge-sa">{{L('labelSuperAdmin')}}</span><span v-if="u.on_vacation" class="badge-vacation">{{L('labelVacation')}}</span></div>
                  <div class="user-email text-muted text-sm">{{u.email}}</div>
                  <div v-if="u.oddzial" class="user-dept text-muted text-sm">{{u.oddzial}}</div>
                </div>
                <div class="col-roles col-stacked">
                  <div class="row-perm" v-if="permanentRolesOf(u).length"><template v-for="r in permanentRolesOf(u).slice(0,3)" :key="r"><span class="role-badge-sm" :style="roleBadgeStyle(r)">{{r}}</span></template><span v-if="permanentRolesOf(u).length>3" class="text-muted text-sm">+{{permanentRolesOf(u).length-3}}</span></div>
                  <div class="row-temp" v-if="tempRolesOf(u).length"><template v-for="r in tempRolesOf(u).slice(0,3)" :key="r"><span class="role-badge-sm role-temp-sm" :style="roleBadgeStyle(r)" :title="tempRoleTooltip(u,r)">{{r}}<span class="temp-icon"><span v-if="content.iconTempIndicator" v-html="getIconHtml('iconTempIndicator')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px'}"></span><template v-else>⏱</template></span></span></template><span v-if="tempRolesOf(u).length>3" class="text-muted text-sm">+{{tempRolesOf(u).length-3}}</span></div>
                </div>
                <div class="col-depts col-stacked">
                  <div class="row-perm" v-if="permanentDepts(u).length"><span class="dept-count-badge">{{userDeptCount(u)}}</span><template v-for="d in permanentDepts(u).slice(0,2)" :key="d.name"><span class="dept-mini">{{d.name}}</span></template><span v-if="permanentDepts(u).length>2" class="text-muted text-sm">+{{permanentDepts(u).length-2}}</span></div>
                  <div class="row-temp" v-if="tempDepts(u).length"><span v-if="!permanentDepts(u).length" class="dept-count-badge">{{userDeptCount(u)}}</span><template v-for="d in tempDepts(u).slice(0,2)" :key="d.name"><span class="dept-mini dept-temp" :title="d.tooltip">{{d.name}}<span class="temp-icon"><span v-if="content.iconTempIndicator" v-html="getIconHtml('iconTempIndicator')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px'}"></span><template v-else>⏱</template></span></span></template><span v-if="tempDepts(u).length>2" class="text-muted text-sm">+{{tempDepts(u).length-2}}</span></div>
                </div>
                <div class="col-clients mono">{{u.visible_clients_count}}</div>
                <div class="col-status"><span class="status-dot" :class="'status-'+u.status"></span><span class="status-text text-sm" :class="'status-text-'+u.status">{{statusLabel(u.status)}}</span></div>
              </div>
              <div v-if="sortedFilteredUsers.length===0" class="empty-state">{{L('labelEmptyUsers')}}</div>
            </div>
            <div v-if="totalPages>1" class="pagination"><button class="btn-ghost" :disabled="currentPage<=1" @click="currentPage--">← {{L('labelPrev')}}</button><span class="text-muted text-sm">{{currentPage}} / {{totalPages}}</span><button class="btn-ghost" :disabled="currentPage>=totalPages" @click="currentPage++">{{L('labelNext')}} →</button></div>
          </div>

          <!-- ROLES -->
          <div v-else-if="activePage==='roles'" class="page">
            <div class="page-title-row"><h1 class="page-title">{{L('labelRoles')}}</h1><button v-if="cap.can_create_roles" class="btn-primary" @click="openModal('createRole')">{{L('labelBtnNewRole')}}</button></div>
            <p class="text-muted text-sm margin-b-md">{{L('labelRolesHint')}}</p>
            <div class="legend-table margin-b-lg">
              <div class="legend-row"><span class="action-badge action-select">select</span><span class="text-muted text-sm">{{L('labelLegendSelect')}}</span></div>
              <div class="legend-row"><span class="action-badge action-insert">insert</span><span class="text-muted text-sm">{{L('labelLegendInsert')}}</span></div>
              <div class="legend-row"><span class="action-badge action-update">update</span><span class="text-muted text-sm">{{L('labelLegendUpdate')}}</span></div>
              <div class="legend-row"><span class="action-badge action-delete">delete</span><span class="text-muted text-sm">{{L('labelLegendDelete')}}</span></div>
              <div class="legend-row"><span class="action-badge action-all">all</span><span class="text-muted text-sm">{{L('labelLegendAll')}}</span></div>
            </div>
            <div v-for="rl in rolesWithTemplates" :key="rl.name" class="card margin-b-sm">
              <div class="role-card-header"><span class="role-badge" :style="roleBadgeStyle(rl.name)">{{rl.name}}</span><span class="text-muted text-sm">{{rl.users_count}} {{L('labelUsersCount')}}</span>
                <div class="role-card-actions"><button v-if="cap.can_create_roles" class="btn-ghost" @click="openEditRole(rl)"><span v-if="content.iconEdit" v-html="getIconHtml('iconEdit')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px',marginRight:'4px'}"></span><template v-else>✎ </template>{{L('labelBtnEditRole')}}</button><button v-if="cap.can_create_roles" class="btn-icon-danger" @click="confirmAction('deleteRole',rl.name)"><span v-if="content.iconDelete" v-html="getIconHtml('iconDelete')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px'}"></span><template v-else>✕</template></button></div>
              </div>
              <div v-if="rl.templates&&rl.templates.length" class="templates-table">
                <div v-for="(t,i) in rl.templates" :key="t.table_name" class="template-row" :class="{last:i===rl.templates.length-1}"><span class="mono">{{t.table_name}}</span><div class="actions-group"><span v-for="a in t.actions" :key="a" class="action-badge" :class="'action-'+a">{{a}}</span></div></div>
              </div>
              <div v-else class="empty-state text-sm">{{L('labelNoTemplates')}}</div>
            </div>
          </div>

          <!-- AUDIT -->
          <div v-else-if="activePage==='audit'" class="page" @click="auditUsersOpen=false">
            <div class="page-title-row"><h1 class="page-title">{{L('labelAudit')}}</h1><button class="btn-ghost" @click="exportCSV('audit')">{{L('labelBtnExport')}}</button></div>
            <div class="toolbar">
              <select class="select-field" v-model="auditFilter" @change="loadAudit(true)"><option value="">{{L('labelAuditAllTables')}}</option><option v-for="t in auditTables" :key="t" :value="t">{{t}}</option></select>
              <div class="audit-users-picker" @click.stop>
                <div class="audit-users-selected" @click="auditUsersOpen=!auditUsersOpen">
                  <template v-if="auditSelectedUsers.length"><span v-for="u in auditSelectedUsers" :key="u.id" class="audit-user-tag">{{u.full_name||u.email}}<button class="tag-remove" @click.stop="toggleAuditUser(u)">✕</button></span></template>
                  <span v-else class="text-muted text-sm">{{L('labelAuditSelectUsers')}}</span>
                </div>
                <div v-if="auditUsersOpen" class="audit-users-dropdown">
                  <input class="input-field" v-model="auditUserSearch" :placeholder="L('labelSearch')" style="margin-bottom:4px;flex:1"/>
                  <div class="audit-users-list">
                    <div v-for="u in filteredAuditUsers" :key="u.id" class="audit-user-option" :class="{selected:auditSelectedUsers.some(s=>s.id===u.id)}" @click="toggleAuditUser(u)">
                      <div class="checkbox" :class="{active:auditSelectedUsers.some(s=>s.id===u.id)}"><span v-if="auditSelectedUsers.some(s=>s.id===u.id)">✓</span></div>{{u.full_name}} <span class="text-muted text-sm">{{u.email}}</span>
                    </div>
                  </div>
                  <button v-if="auditSelectedUsers.length" class="btn-ghost full-width margin-t-sm" style="font-size:11px" @click="auditSelectedUsers=[];auditUsersOpen=false;loadAudit(true)">{{L('labelClearAll')}}</button>
                </div>
              </div>
              <input class="input-field" v-model="auditUser" :placeholder="L('labelAuditEmailPlaceholder')" @input="debounceAudit"/>
            </div>
            <div class="toolbar margin-t-sm">
              <input type="date" class="input-field input-date" v-model="auditFrom" @change="loadAudit(true)"/>
              <span class="text-muted text-sm" style="display:flex;align-items:center">—</span>
              <input type="date" class="input-field input-date" v-model="auditTo" @change="loadAudit(true)"/>
              <button class="btn-ghost" @click="setAuditDatePreset('today')">{{L('labelToday')}}</button>
              <button class="btn-ghost" @click="setAuditDatePreset('7d')">7 {{L('labelDays')}}</button>
              <button class="btn-ghost" @click="setAuditDatePreset('30d')">30 {{L('labelDays')}}</button>
              <button v-if="auditFrom||auditTo" class="btn-ghost" @click="auditFrom='';auditTo='';loadAudit(true)">{{L('labelClearAll')}}</button>
            </div>
            <div class="audit-info text-muted text-sm" v-if="!auditLoading">{{L('labelAuditShowing')}} {{auditLogs.length}} {{L('labelOf')}} {{auditTotal}}</div>
            <div class="card no-pad">
              <div v-if="auditLoading" class="loader" style="min-height:120px"><div class="spinner"></div></div>
              <template v-else>
                <div v-for="(a,i) in auditLogs" :key="a.id" class="audit-row" :class="{last:i===auditLogs.length-1}">
                  <div class="audit-top"><div class="audit-left"><span class="audit-table-badge">{{a.table_label||a.table_name}}</span><span v-if="a.action_type" class="action-badge" :class="'action-'+a.action_type">{{a.action_type}}</span></div><span class="text-muted text-sm">{{formatDate(a.created_at)}}</span></div>
                  <div class="audit-description">{{a.human_description||a.description}}</div>
                  <div v-if="a.details" class="audit-details text-muted text-sm">{{a.details}}</div>
                  <div class="text-muted text-sm">{{a.user_name||a.user_email}}</div>
                </div>
                <div v-if="auditLogs.length===0" class="empty-state">{{L('labelEmptyAudit')}}</div>
              </template>
            </div>
            <div v-if="auditTotalPages>1" class="pagination"><button class="btn-ghost" :disabled="auditPage<=1" @click="auditPage--;loadAudit()">← {{L('labelPrev')}}</button><span class="text-muted text-sm">{{auditPage}} / {{auditTotalPages}}</span><button class="btn-ghost" :disabled="auditPage>=auditTotalPages" @click="auditPage++;loadAudit()">{{L('labelNext')}} →</button></div>
          </div>

          <!-- TEMP GRANTS -->
          <div v-else-if="activePage==='temp'" class="page">
            <div class="page-title-row"><h1 class="page-title">{{L('labelTemp')}}</h1><button class="btn-ghost" @click="exportCSV('temp')">{{L('labelBtnExport')}}</button></div>
            <div class="card no-pad">
              <div v-for="(g,i) in tempGrants" :key="g.id" class="audit-row" :class="{last:i===tempGrants.length-1}">
                <div class="audit-top"><div class="audit-left"><span class="role-badge-sm" :style="g.grant_type==='role'?roleBadgeStyle(g.role_name):{}">{{g.grant_type==='role'?g.role_name:g.oddzial_name}}</span><span class="text-muted text-sm">→ {{g.user_name}}</span></div><span class="temp-countdown" :class="{urgent:isUrgent(g.expires_at)}">{{formatTimeRemaining(g.time_remaining)}}</span></div>
                <div class="text-sm text-muted">{{L('labelGrantedBy')}}: {{g.created_by}}<template v-if="g.reason"> — {{g.reason}}</template></div>
                <div class="text-sm text-muted">{{L('labelGrantedAt')}}: {{formatDate(g.created_at)}}</div>
                <div class="text-sm text-muted">{{L('labelExpiresAt')}}: {{formatDate(g.expires_at)}}</div>
                <div v-if="g.extension_history&&g.extension_history.length" class="ext-history">
                  <div v-for="(ext,ei) in g.extension_history" :key="ei" class="ext-entry text-sm text-muted"><span class="ext-label">{{L('labelExtended')}}</span> {{formatDate(ext.extended_at)}} {{L('labelExtendedBy')}} {{ext.extended_by}}: {{formatDate(ext.old_expires_at)}} → {{formatDate(ext.new_expires_at)}}<template v-if="ext.reason"> — {{ext.reason}}</template></div>
                </div>
                <div class="temp-grant-actions"><button class="btn-ghost" @click="extendGrant(g)">{{L('labelBtnExtend')}}</button><button class="btn-ghost btn-danger" @click="confirmAction('revokeGrant',g)">{{L('labelBtnRevoke')}}</button></div>
              </div>
              <div v-if="tempGrants.length===0" class="empty-state">{{L('labelEmptyTemp')}}</div>
            </div>
          </div>

          <!-- PERMISSION MATRIX -->
          <div v-else-if="activePage==='matrix'" class="page">
            <h1 class="page-title">{{L('labelMatrix')||'Matryca uprawnień'}}</h1>
            <div class="toolbar margin-b-md">
              <select class="select-field" v-model="matrixRoleFilter"><option value="">{{L('labelAllRoles')}}</option><option v-for="r in allRoles" :key="r" :value="r">{{r}}</option></select>
            </div>
            <div class="legend-table margin-b-md">
              <div class="legend-row"><span class="action-badge action-select">S</span><span class="text-muted text-sm">select — {{L('labelLegendSelect')}}</span></div>
              <div class="legend-row"><span class="action-badge action-insert">I</span><span class="text-muted text-sm">insert — {{L('labelLegendInsert')}}</span></div>
              <div class="legend-row"><span class="action-badge action-update">U</span><span class="text-muted text-sm">update — {{L('labelLegendUpdate')}}</span></div>
              <div class="legend-row"><span class="action-badge action-delete">D</span><span class="text-muted text-sm">delete — {{L('labelLegendDelete')}}</span></div>
            </div>
            <div class="card no-pad matrix-scroll">
              <table class="matrix-table">
                <thead><tr><th class="matrix-user-col">{{L('labelColUser')}}</th><th v-for="t in availableTables" :key="t" class="matrix-table-col" :title="t"><span class="matrix-table-name">{{t}}</span></th></tr></thead>
                <tbody>
                  <tr v-for="u in matrixUsers" :key="u.id">
                    <td class="matrix-user-cell"><div style="font-size:12px;font-weight:600">{{u.full_name}}</div></td>
                    <td v-for="t in availableTables" :key="t" class="matrix-cell">
                      <template v-if="u.permissions&&u.permissions[t]">
                        <span v-for="a in (Array.isArray(u.permissions[t])?u.permissions[t]:[u.permissions[t]])" :key="a" class="matrix-action" :class="'action-'+a" :title="a">{{a[0].toUpperCase()}}</span>
                      </template>
                      <span v-else class="matrix-empty">—</span>
                    </td>
                  </tr>
                </tbody>
              </table>
            </div>
          </div>

          <!-- REQUESTS -->
          <div v-else-if="activePage==='requests'" class="page">
            <h1 class="page-title">{{L('labelRequests')||'Wnioski o dostęp'}}</h1>

            <!-- Admin: pending requests -->
            <template v-if="isAdmin&&accessRequests.length">
              <div class="section-label">Oczekujące wnioski ({{accessRequests.length}})</div>
              <div class="card no-pad margin-b-lg">
                <div v-for="(r,i) in accessRequests" :key="r.id" class="audit-row" :class="{last:i===accessRequests.length-1}">
                  <div class="audit-top"><div class="audit-left"><span class="role-badge-sm" :style="r.request_type==='role'?roleBadgeStyle(r.role_name):{}">{{r.request_type==='role'?r.role_name:r.oddzial_name}}</span><span class="text-muted text-sm">→ {{r.target_user_name}}</span></div><span class="text-muted text-sm">{{formatDate(r.created_at)}}</span></div>
                  <div class="text-sm">Od: {{r.requested_by_name}}</div>
                  <div v-if="r.reason" class="text-sm text-muted">Powód: {{r.reason}}</div>
                  <div class="request-actions">
                    <input class="input-field" v-model="reviewComment" placeholder="Komentarz (opcjonalnie)" style="flex:1"/>
                    <div class="request-btns">
                      <button class="btn-primary" :class="{'btn-loading':actionLoading==='review'}" @click="reviewRequest(r.id,'approved')" :disabled="actionLoading">Zaakceptuj</button>
                      <button class="btn-ghost btn-danger" :class="{'btn-loading':actionLoading==='review'}" @click="reviewRequest(r.id,'rejected')" :disabled="actionLoading">Odrzuć</button>
                    </div>
                  </div>
                </div>
              </div>
            </template>

            <!-- Create new request -->
            <div class="section-label">Nowy wniosek</div>
            <div class="card no-pad">
              <div class="request-form-section">
                <div class="section-label text-sm">Dla kogo</div>
                <select class="select-field" v-model="newRequestTarget"><option value="">— Wybierz pracownika —</option><option v-for="u in users" :key="u.id" :value="u.id">{{u.full_name}} ({{u.email}})</option></select>
              </div>
              <div class="request-form-section">
                <div class="section-label text-sm">Role</div>
                <div class="roles-wrap"><span v-for="r in allRoles" :key="r" class="role-badge clickable" :style="roleBadgeStyle(r)" :class="{dimmed:!newRequestRoles.includes(r)}" @click="toggleRequestRole(r)">{{r}}<span v-if="newRequestRoles.includes(r)" class="change-dot green" style="font-size:8px">✓</span></span></div>
              </div>
              <div class="request-form-section">
                <div class="section-label text-sm">Oddziały</div>
                <div class="odz-grid"><div v-for="o in allOdz" :key="o.id" class="odz-checkbox" :class="{checked:newRequestDepts.includes(o.id)}" @click="toggleRequestDept(o.id)"><div class="checkbox" :class="{active:newRequestDepts.includes(o.id)}"><span v-if="newRequestDepts.includes(o.id)">✓</span></div>{{o.name}}</div></div>
              </div>
              <div class="request-form-section">
                <div class="section-label text-sm">Powód (opcjonalnie)</div>
                <input class="input-field" v-model="newRequestReason" placeholder="np. nowy projekt wymaga dostępu do..."/>
              </div>
              <div v-if="newRequestRoles.length||newRequestDepts.length||newRequestTarget" class="request-form-section request-summary">
                <div class="section-label text-sm">Podsumowanie wniosku</div>
                <div v-if="newRequestTarget" class="text-sm">Dla: <strong>{{users.find(u=>u.id===newRequestTarget)?.full_name||'—'}}</strong></div>
                <div v-if="newRequestRoles.length" class="text-sm">Role ({{newRequestRoles.length}}): <span v-for="r in newRequestRoles" :key="r" class="role-badge-sm" :style="roleBadgeStyle(r)" style="margin-right:4px">{{r}}</span></div>
                <div v-if="newRequestDepts.length" class="text-sm">Oddziały ({{newRequestDepts.length}}): {{newRequestDepts.map(id=>{const o=allOdz.find(x=>x.id===id);return o?o.name:id}).join(', ')}}</div>
                <div v-if="newRequestReason" class="text-sm text-muted">Powód: {{newRequestReason}}</div>
              </div>
              <div class="request-form-footer">
                <button v-if="newRequestRoles.length||newRequestDepts.length||newRequestTarget" class="btn-ghost" @click="resetRequestForm">Wyczyść formularz</button>
                <button class="btn-primary" :class="{'btn-loading':actionLoading==='submitRequest'}" @click="submitAccessRequest" :disabled="!newRequestTarget||(!newRequestRoles.length&&!newRequestDepts.length)||actionLoading"><span v-if="actionLoading==='submitRequest'" class="btn-spinner"></span>Wyślij wniosek ({{newRequestRoles.length+newRequestDepts.length}})</button>
              </div>
            </div>

            <!-- My requests history -->
            <div v-if="myRequests.length" class="margin-t-lg">
              <div class="section-label">Moje wnioski</div>
              <div class="card no-pad">
                <div v-for="(r,i) in myRequests" :key="r.id" class="audit-row" :class="{last:i===myRequests.length-1}">
                  <div class="audit-top"><div class="audit-left"><span class="role-badge-sm" :style="r.request_type==='role'?roleBadgeStyle(r.role_name):{}">{{r.request_type==='role'?r.role_name:r.oddzial_name}}</span><span class="text-muted text-sm">→ {{r.target_user_name}}</span></div><span class="status-text text-sm" :class="{'text-green':r.status==='approved','text-red':r.status==='rejected'}">{{r.status==='pending'?'Oczekuje':r.status==='approved'?'Zaakceptowany':'Odrzucony'}}</span></div>
                  <div class="text-muted text-sm">{{formatDate(r.created_at)}}</div>
                  <div v-if="r.review_comment" class="text-sm">Komentarz: {{r.review_comment}}</div>
                  <div v-if="r.reviewer_name" class="text-muted text-sm">Rozpatrzony przez: {{r.reviewer_name}}</div>
                </div>
              </div>
            </div>
          </div>
        </main>
      </div>

      <!-- USER DETAIL PANEL -->
      <div v-if="selectedUser" class="overlay" @click.self="closeAllModals">
        <div class="detail-panel">
          <div class="detail-header">
            <div>
              <div class="detail-name">{{selectedUser.full_name}}<span v-if="selectedUser.is_super_admin" class="badge-sa">SA</span></div>
              <div class="text-muted text-sm">{{selectedUser.email}}</div>
              <div class="text-muted text-sm">{{L('labelDept')}}: {{selectedUser.oddzial||'—'}}</div>
              <div class="text-muted text-sm">{{L('labelColStatus')}}: <span class="status-text" :class="'status-text-'+selectedUser.status">{{statusLabel(selectedUser.status)}}</span></div>
            </div>
            <button class="btn-close" @click="closeAllModals"><span v-if="content.iconClose" v-html="getIconHtml('iconClose')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px'}"></span><template v-else>✕</template></button>
          </div>
          <div class="detail-actions">
            <button class="btn-primary" @click="openModal('copy')">{{L('labelBtnCopy')}}</button>
            <button class="btn-secondary" @click="openModal('addRole')">{{L('labelBtnAddRole')}}</button>
            <button v-if="cap.can_grant_temporary" class="btn-secondary" @click="openModal('tempGrant')">{{L('labelBtnTempAccess')}}</button>
          </div>
          <div class="detail-tabs"><button v-for="t in detailTabs" :key="t.id" class="detail-tab" :class="{active:detailTab===t.id}" @click="detailTab=t.id;if(t.id==='history')loadUserHistory()">{{t.label}}</button></div>
          <div class="detail-body">
            <div v-if="detailTab==='roles'">
              <div class="section-label">{{L('labelAssignedRoles')}}</div>
              <div class="roles-wrap">
                <span v-for="r in uniqueRoles(selectedUser)" :key="r" class="role-badge" :class="{'role-temp':isTempRole(selectedUser,r)}" :style="roleBadgeStyle(r)">{{r}}<span v-if="isTempRole(selectedUser,r)" class="temp-icon" :title="tempRoleTooltip(selectedUser,r)"><span v-if="content.iconTempIndicator" v-html="getIconHtml('iconTempIndicator')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px'}"></span><template v-else>⏱</template></span><button class="role-remove" @click="confirmAction('removeRole',{uid:selectedUser.id,role:r})"><span v-if="content.iconClose" v-html="getIconHtml('iconClose')" class="icon-svg" :style="{width:'12px',height:'12px'}"></span><template v-else>✕</template></button></span>
                <span v-if="!uniqueRoles(selectedUser).length" class="text-muted text-sm">{{L('labelNoRoles')}}</span>
              </div>
              <div class="section-label margin-t-lg">{{L('labelPermissions')}}<span v-if="selectedUser.is_auto_generated" class="auto-badge">{{L('labelAutoFromRoles')}}</span><button v-if="cap.can_create_roles" class="btn-ghost" style="margin-left:auto" @click="openEditPermissions"><span v-if="content.iconEdit" v-html="getIconHtml('iconEdit')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px',marginRight:'4px'}"></span><template v-else>✎ </template>{{L('labelBtnEditPerms')}}</button></div>
              <div class="permissions-list">
                <div v-for="(acts,tbl) in (selectedUser.permissions||{})" :key="tbl" class="permission-row"><span class="mono">{{tbl}}</span><div class="actions-group"><span v-for="a in (Array.isArray(acts)?acts:[acts])" :key="a" class="action-badge" :class="'action-'+a">{{a}}</span></div></div>
                <div v-if="!Object.keys(selectedUser.permissions||{}).length" class="empty-state text-sm">{{selectedUser.is_super_admin?L('labelSuperAdminAccess'):L('labelNoPermissions')}}</div>
              </div>
            </div>
            <div v-if="detailTab==='visibility'"><div class="big-number">{{selectedUser.visible_clients_count}}</div><div class="text-muted text-sm" style="text-align:center">{{L('labelVisibleClients')}}</div></div>
            <div v-if="detailTab==='departments'">
              <div class="section-label">{{L('labelUserDepts')}}</div>
              <div v-if="userHasAllDepts(selectedUser)" class="text-muted text-sm margin-b-md" style="font-style:italic">{{L('labelAllDeptsAccess')}}</div>
              <div class="odz-grid">
                <div v-for="o in allOdz" :key="o.id" class="odz-view-item" :class="{'odz-active':userHasDept(selectedUser,o.id),'odz-inactive':!userHasDept(selectedUser,o.id),'odz-temp':isTempDept(selectedUser,o.id)}" :title="isTempDept(selectedUser,o.id)?tempDeptTooltip(selectedUser,o.id):''">
                  <div class="odz-indicator" :class="{'odz-indicator-on':userHasDept(selectedUser,o.id)&&!isTempDept(selectedUser,o.id),'odz-indicator-off':!userHasDept(selectedUser,o.id),'odz-indicator-temp':isTempDept(selectedUser,o.id)}"></div>{{o.name}}<span v-if="isTempDept(selectedUser,o.id)" class="temp-icon"><span v-if="content.iconTempIndicator" v-html="getIconHtml('iconTempIndicator')" class="icon-svg" :style="{width:content.iconSize||'14px',height:content.iconSize||'14px'}"></span><template v-else>⏱</template></span>
                  <button v-if="userHasDept(selectedUser,o.id)&&!userHasAllDepts(selectedUser)" class="dept-remove" @click.stop="confirmAction('removeDept',{uid:selectedUser.id,deptId:o.id,deptName:o.name})"><span v-if="content.iconClose" v-html="getIconHtml('iconClose')" class="icon-svg" :style="{width:'10px',height:'10px'}"></span><template v-else>✕</template></button>
                  <button v-if="!userHasDept(selectedUser,o.id)" class="dept-add" @click.stop="addDept(selectedUser.id,o.id,o.name)">+</button>
                </div>
              </div>
              <div class="text-muted text-sm margin-t-md" style="text-align:center">{{countUserDepts(selectedUser)}} {{L('labelOf')}} {{allOdz.length}} {{L('labelDepartments').toLowerCase()}}</div>
            </div>
            <div v-if="detailTab==='history'">
              <div v-if="userHistoryLoading" class="loader" style="min-height:80px"><div class="spinner"></div></div>
              <div v-else-if="!userHistory.length" class="empty-state text-sm">Brak historii zmian</div>
              <div v-else class="timeline">
                <div v-for="h in paginatedHistory" :key="h.id" class="timeline-item">
                  <div class="timeline-dot" :class="{'timeline-own':h.is_own_action}"></div>
                  <div class="timeline-content">
                    <div class="timeline-top"><span v-if="h.action_type" class="action-badge" :class="'action-'+h.action_type">{{h.action_type}}</span><span v-if="h.table_name" class="audit-table-badge">{{h.table_name}}</span><span class="text-muted text-sm" style="margin-left:auto">{{formatDate(h.created_at)}}</span></div>
                    <div class="timeline-desc">{{h.human_description||h.description}}</div>
                    <div v-if="h.details" class="text-muted text-sm">{{h.details}}</div>
                    <div class="text-muted text-sm">{{h.user_name||h.user_email}}</div>
                  </div>
                </div>
              </div>
              <div v-if="historyTotalPages>1" class="pagination"><button class="btn-ghost" :disabled="historyPage<=1" @click="historyPage--">← {{L('labelPrev')}}</button><span class="text-muted text-sm">{{historyPage}} / {{historyTotalPages}}</span><button class="btn-ghost" :disabled="historyPage>=historyTotalPages" @click="historyPage++">{{L('labelNext')}} →</button></div>
            </div>
          </div>
        </div>
      </div>

      <!-- ADD ROLE MODAL -->
      <div v-if="activeModal==='addRole'&&selectedUser" class="overlay" @click.self="activeModal=null"><div class="modal"><div class="modal-title">{{L('labelAddRoleFor')}} {{selectedUser.full_name}}</div><div class="roles-wrap"><span v-for="r in availableRoles" :key="r" class="role-badge clickable" :style="roleBadgeStyle(r)" @click="addRole(selectedUser.id,r)">{{r}}</span><span v-if="!availableRoles.length" class="text-muted text-sm">{{L('labelAllRolesAssigned')}}</span></div></div></div>

      <!-- COPY MODAL -->
      <div v-if="activeModal==='copy'&&selectedUser" class="overlay" @click.self="closeCopyModal"><div class="modal modal-wide">
        <template v-if="copyStep===1"><div class="modal-title">{{L('labelCopyFrom')}} {{selectedUser.full_name}}</div><div class="text-muted text-sm margin-b-md">{{L('labelSelectTarget')}}</div><input class="input-field margin-b-sm" v-model="copySearch" :placeholder="L('labelSearch')"/><div v-for="u in copyTargets" :key="u.id" class="copy-target" @click="selectCopyTarget(u)"><div class="copy-avatar">{{initials(u.full_name)}}</div><div class="copy-info"><div style="font-weight:600">{{u.full_name}}</div><div class="text-muted text-sm">{{u.email}}</div></div></div></template>
        <template v-if="copyStep===2"><div class="modal-title">{{L('labelReviewCopy')}}</div><div class="text-muted text-sm margin-b-md">{{copyTarget.full_name}} → {{selectedUser.full_name}}</div>
          <div class="copy-action-row"><button class="btn-secondary" @click="copyStep=1">← {{L('labelChangeTarget')}}</button><button class="btn-primary" :class="{modified:copyHasChanges,'btn-loading':actionLoading==='applyCopy'}" @click="applyCopy" :disabled="actionLoading"><span v-if="actionLoading==='applyCopy'" class="btn-spinner"></span>{{copyHasChanges?L('labelBtnApplyModified'):L('labelBtnApply')}}</button></div>
          <div class="section-label">{{L('labelRoles')}}<span v-if="copyAdded.length||copyRemoved.length" class="change-hint">{{copyAdded.length?'+'+copyAdded.length:''}}{{copyRemoved.length?' -'+copyRemoved.length:''}} {{L('labelChanged')}}</span></div>
          <div class="roles-wrap"><span v-for="r in allRoles" :key="r" class="role-badge clickable" :style="roleBadgeStyle(r)" :class="{dimmed:!copyRoles.includes(r)}" @click="toggleCopyRole(r)">{{r}}<span v-if="copyRoles.includes(r)&&!sourceRoles.includes(r)" class="change-dot green">+</span><span v-if="!copyRoles.includes(r)&&sourceRoles.includes(r)" class="change-dot red">−</span></span></div>
          <div class="section-label margin-t-md">{{L('labelDepartments')}}<span v-if="copyOdzAdded.length||copyOdzRemoved.length" class="change-hint">{{copyOdzAdded.length?'+'+copyOdzAdded.length:''}}{{copyOdzRemoved.length?' -'+copyOdzRemoved.length:''}} {{L('labelChanged')}}</span></div>
          <div class="odz-actions"><button class="btn-ghost" @click="copyOdz=allOdz.map(o=>o.id)">{{L('labelSelectAll')}}</button><button class="btn-ghost" @click="copyOdz=[]">{{L('labelClearAll')}}</button></div>
          <div class="odz-grid"><div v-for="o in allOdz" :key="o.id" class="odz-checkbox" :class="{checked:copyOdz.includes(o.id)}" @click="toggleCopyOdz(o.id)"><div class="checkbox" :class="{active:copyOdz.includes(o.id)}"><span v-if="copyOdz.includes(o.id)"><span v-if="content.iconCheckmark" v-html="getIconHtml('iconCheckmark')" class="icon-svg" :style="{width:'10px',height:'10px'}"></span><template v-else>✓</template></span></div>{{o.name}}<span v-if="copyOdz.includes(o.id)&&!sourceOdz.includes(o.id)" class="change-dot green">+</span><span v-if="!copyOdz.includes(o.id)&&sourceOdz.includes(o.id)" class="change-dot red">−</span></div></div>
          <div class="copy-summary"><div class="section-label text-sm">{{L('labelSummary')}}</div><div class="text-muted text-sm">{{L('labelTarget')}}: <strong>{{copyTarget.full_name}}</strong></div><div class="text-muted text-sm">{{L('labelRoles')}} ({{copyRoles.length}}): {{copyRoles.join(', ')||L('labelNone')}}</div><div v-if="copyAdded.length" class="text-sm text-green">+ {{copyAdded.join(', ')}}</div><div v-if="copyRemoved.length" class="text-sm text-red">− {{copyRemoved.join(', ')}}</div><div class="text-muted text-sm">{{L('labelDepartments')}}: {{copyOdz.length}} {{L('labelOf')}} {{allOdz.length}}</div><div v-if="copyOdzAdded.length" class="text-sm text-green">+ {{copyOdzAdded.map(id=>{const o=allOdz.find(x=>x.id===id);return o?o.name:id}).join(', ')}}</div><div v-if="copyOdzRemoved.length" class="text-sm text-red">− {{copyOdzRemoved.map(id=>{const o=allOdz.find(x=>x.id===id);return o?o.name:id}).join(', ')}}</div></div>
        </template>
      </div></div>

      <!-- TEMP GRANT MODAL -->
      <div v-if="activeModal==='tempGrant'&&selectedUser" class="overlay" @click.self="activeModal=null"><div class="modal modal-wide">
        <div class="modal-title">{{L('labelTempAccessFor')}} {{selectedUser.full_name}}</div>
        <div class="section-label">{{L('labelTempType')}}</div>
        <div class="toggle-group"><button class="toggle-btn" :class="{active:tempGrantType==='role'}" @click="tempGrantType='role';tempGrantRole='';tempGrantOdz=[]">{{L('labelTempRole')}}</button><button class="toggle-btn" :class="{active:tempGrantType==='oddzial'}" @click="tempGrantType='oddzial';tempGrantRole='';tempGrantOdz=[]">{{L('labelTempDept')}}</button></div>
        <template v-if="tempGrantType==='role'"><div class="section-label">{{L('labelSelectRole')}}</div><div class="roles-wrap"><span v-for="r in tempAvailableRoles" :key="r" class="role-badge clickable" :style="roleBadgeStyle(r)" :class="{'role-selected':tempGrantRole===r}" @click="tempGrantRole=r">{{r}}</span><span v-if="!tempAvailableRoles.length" class="text-muted text-sm">{{L('labelAllRolesAssigned')}}</span></div></template>
        <template v-if="tempGrantType==='oddzial'"><div class="section-label">{{L('labelSelectDepts')}}</div><div class="odz-grid"><div v-for="o in tempAvailableDepts" :key="o.id" class="odz-checkbox" :class="{checked:tempGrantOdz.includes(o.id)}" @click="toggleTempOdz(o.id)"><div class="checkbox" :class="{active:tempGrantOdz.includes(o.id)}"><span v-if="tempGrantOdz.includes(o.id)"><span v-if="content.iconCheckmark" v-html="getIconHtml('iconCheckmark')" class="icon-svg" :style="{width:'10px',height:'10px'}"></span><template v-else>✓</template></span></div>{{o.name}}</div></div><span v-if="!tempAvailableDepts.length" class="text-muted text-sm">{{L('labelAllDeptsAssigned')}}</span></template>
        <div class="section-label margin-t-md">{{L('labelTempExpires')}}</div><input type="datetime-local" class="input-field" v-model="tempGrantExp" :min="minDateTimeLocal"/>
        <div class="section-label margin-t-md">{{L('labelTempReason')}}</div><input class="input-field" v-model="tempGrantReason" :placeholder="L('labelTempReasonPlaceholder')"/>
        <button class="btn-primary margin-t-md full-width" :class="{'btn-loading':actionLoading==='applyTempGrant'}" @click="applyTempGrant" :disabled="!canApplyTempGrant||actionLoading"><span v-if="actionLoading==='applyTempGrant'" class="btn-spinner"></span>{{L('labelTempApply')}}</button>
      </div></div>

      <!-- EXTEND MODAL -->
      <div v-if="activeModal==='extend'" class="overlay" @click.self="activeModal=null"><div class="modal"><div class="modal-title">{{L('labelExtendAccess')}}</div><div class="section-label margin-t-sm">{{L('labelNewExpiry')}}</div><input type="datetime-local" class="input-field" v-model="extendDate" :min="minDateTimeLocal"/><div class="section-label margin-t-md">{{L('labelExtendReason')}}</div><input class="input-field" v-model="extendReason" :placeholder="L('labelExtendReasonPlaceholder')"/><button class="btn-primary margin-t-md full-width" @click="doExtend" :disabled="!extendDate">{{L('labelSave')}}</button></div></div>

      <!-- CREATE ROLE MODAL -->
      <div v-if="activeModal==='createRole'" class="overlay" @click.self="activeModal=null"><div class="modal modal-wide">
        <div class="modal-title">{{L('labelNewRole')}}</div><input class="input-field margin-b-sm" v-model="newRoleName" :placeholder="L('labelRoleNamePlaceholder')"/>
        <div class="section-label margin-t-sm">{{L('labelRoleColor')}}</div><div class="color-row"><label class="color-label">BG: <input type="color" v-model="newRoleColorBg" class="color-input"/></label><label class="color-label">Text: <input type="color" v-model="newRoleColorFg" class="color-input"/></label><span class="role-badge" :style="{backgroundColor:newRoleColorBg,color:newRoleColorFg}">{{newRoleName||'PREVIEW'}}</span></div>
        <div v-if="contrastWarning(newRoleColorBg,newRoleColorFg)" class="contrast-warning">⚠ {{contrastWarning(newRoleColorBg,newRoleColorFg)}}</div>
        <div class="section-label margin-t-md">{{L('labelTemplates')}}</div>
