    sortedFilteredUsers(){const arr=[...this.filteredUsers];const f=this.sortField;const d=this.sortDir==='asc'?1:-1;arr.sort((a,b)=>{let va,vb;if(f==='full_name'){va=(a.full_name||'').toLowerCase();vb=(b.full_name||'').toLowerCase()}else if(f==='roles'){va=(a.roles||[]).length;vb=(b.roles||[]).length}else if(f==='visible_clients_count'){va=a.visible_clients_count||0;vb=b.visible_clients_count||0}else if(f==='status'){const so={active:0,vacation:1,inactive:2,terminated:3};va=so[a.status]??4;vb=so[b.status]??4}else if(f==='depts'){va=this.countUserDepts(a);vb=this.countUserDepts(b)}else{va=a[f];vb=b[f]}if(va<vb)return-d;if(va>vb)return d;return 0});return arr},
