    matrixUsers(){if(!this.matrixRoleFilter)return this.users;return this.users.filter(u=>(u.roles||[]).includes(this.matrixRoleFilter))},
    searchSuggestions(){if(!this.searchQuery||this.searchQuery.length<2)return[];const q=this.searchQuery.toLowerCase();return this.users.filter(u=>u.full_name.toLowerCase().includes(q)||u.email.toLowerCase().includes(q)).slice(0,5)},
    auditTotalPages(){return Math.max(1,Math.ceil(this.auditTotal/AUDIT_PER_PAGE))},
    filteredAuditUsers(){const q=(this.auditUserSearch||'').toLowerCase();return this.users.filter(u=>!q||u.full_name.toLowerCase().includes(q)||u.email.toLowerCase().includes(q))},
    availableRoles(){if(!this.selectedUser)return[];return this.allRoles.filter(r=>!this.uniqueRoles(this.selectedUser).includes(r))},
    tempAvailableRoles(){if(!this.selectedUser)return[];const ex=this.uniqueRoles(this.selectedUser);const at=this.tempGrants.filter(g=>g.grant_type==='role'&&g.user_id===this.selectedUser.id).map(g=>g.role_name);return this.allRoles.filter(r=>!ex.includes(r)&&!at.includes(r))},
    copyTargets(){if(!this.selectedUser)return[];return this.users.filter(u=>u.id!==this.selectedUser.id&&(!this.copySearch||u.full_name.toLowerCase().includes(this.copySearch.toLowerCase())||u.email.toLowerCase().includes(this.copySearch.toLowerCase())))},
    sourceRoles(){return this.copyTarget?(this.copyTarget.roles||[]):[]},
