    toggleSort(field){if(this.sortField===field){this.sortDir=this.sortDir==='asc'?'desc':'asc'}else{this.sortField=field;this.sortDir='asc'}this.currentPage=1},
    sortIcon(field){if(this.sortField!==field)return'⇅';return this.sortDir==='asc'?'↑':'↓'},
    selectSuggestion(u){this.searchQuery=u.full_name;this.searchSuggestionsOpen=false},
    openModal(n){this.activeModal=n},closeAllModals(){this.activeModal=null;this.selectedUser=null;this.confirmModal=null},
    async initSupabase(){if(this._initInProgress)return;this._initInProgress=true;try{if(typeof wwLib!=='undefined'){const i=wwLib?.wwPlugins?.supabase?.instance||wwLib?.wwPlugins?.supabaseAuth?.publicInstance;if(i){this.supabase=i;await this.loadAll();return}}const u=this.content.supabaseUrl,k=this.content.supabaseAnonKey;if(u&&k){this.supabase=createClient(u,k);await this.loadAll();return}this.supabase=null}catch(e){console.warn('initSupabase failed:',e.message);this.showToast('Błąd połączenia z Supabase','error')}finally{this._initInProgress=false}},
    async loadAll(){this.loading=true;const r=await Promise.allSettled([this.supabase.rpc('admin_dashboard_stats'),this.supabase.rpc('get_admin_users_overview'),this.supabase.rpc('admin_get_my_capabilities'),this.supabase.rpc('admin_get_roles_with_templates'),this.supabase.from('oddzialy').select('id,oddzial').order('oddzial'),this.supabase.rpc('admin_get_available_tables')]);if(r[0].status==='fulfilled'&&!r[0].value.error)this.stats=r[0].value.data||{};else this.showToast('Nie udało się załadować statystyk','error');if(r[1].status==='fulfilled'&&!r[1].value.error){const raw=r[1].value.data;this.users=Array.isArray(raw)?raw:(raw||[])}else this.showToast('Nie udało się załadować użytkowników','error');if(r[2].status==='fulfilled'&&!r[2].value.error)this.cap=r[2].value.data||{};if(r[3].status==='fulfilled'&&!r[3].value.error)this.processRolesData(r[3].value.data);else this.showToast('Nie udało się załadować ról','error');if(r[4].status==='fulfilled'&&!r[4].value.error)this.allOdz=(r[4].value.data||[]).map(x=>({id:x.id,name:x.oddzial}));if(r[5].status==='fulfilled'&&!r[5].value.error){this.availableTables=(r[5].value.data||[]).map(t=>t.name)}await this.loadTempGrants();this.loadRequests();this.initChartDates();await Promise.allSettled([this.loadChart(),this.loadDeptStats()]);this.rolesWithTemplates.forEach(rl=>(rl.templates||[]).forEach(t=>{if(!this.availableTables.includes(t.table_name))this.availableTables.push(t.table_name)}));this.availableTables.sort();this.auditTables=[...this.availableTables];this.loading=false},
    processRolesData(d){this.rolesWithTemplates=d||[];this.allRoles=this.rolesWithTemplates.map(x=>x.name);const m={};for(const r of this.rolesWithTemplates){if(r.color_bg&&r.color_fg)m[r.name]={bg:r.color_bg,fg:r.color_fg}}this.roleColorsMap=m},
    async refreshStats(){try{const{data,error}=await this.supabase.rpc('admin_dashboard_stats');if(!error)this.stats=data||{};await Promise.allSettled([this.loadChart(),this.loadDeptStats()])}catch(e){console.warn('refreshStats failed:',e.message)}},
    async refreshUsers(){try{const{data,error}=await this.supabase.rpc('get_admin_users_overview');if(!error)this.users=Array.isArray(data)?data:(data||[])}catch(e){this.showToast('Nie udało się odświeżyć','error')}},
    uniqueRoles(u){return[...new Set(u?.roles||[])]},
    permanentRolesOf(u){return this.uniqueRoles(u).filter(r=>!this.isTempRole(u,r))},
    tempRolesOf(u){return this.uniqueRoles(u).filter(r=>this.isTempRole(u,r))},
    sortedRoles(u){return[...this.permanentRolesOf(u),...this.tempRolesOf(u)]},
    permanentDepts(u){if(!u)return[];const ids=u.allowed_oddzial_ids;const isAll=ids===null||ids===undefined;return this.allOdz.filter(o=>isAll||(Array.isArray(ids)&&ids.includes(o.id))).filter(o=>!this.isTempDept(u,o.id)).map(o=>({name:o.name,isTemp:false}))},
    tempDepts(u){if(!u)return[];return this.allOdz.filter(o=>this.isTempDept(u,o.id)).map(o=>{const g=this.tempGrants.find(g=>g.grant_type==='oddzial'&&g.oddzial_id===o.id&&g.user_id===u.id);return{name:o.name,isTemp:true,tooltip:this.tempDeptTooltip(u,o.id),timeLeft:g?this.formatTimeRemaining(g.time_remaining):'',urgent:g?this.isUrgent(g.expires_at):false}})},
    sortedDepts(u){return[...this.permanentDepts(u),...this.tempDepts(u)]},
    async loadAudit(reset){if(reset)this.auditPage=1;this.auditLoading=true;try{const off=(this.auditPage-1)*AUDIT_PER_PAGE;const emails=[];if(this.auditSelectedUsers.length)this.auditSelectedUsers.forEach(u=>emails.push(u.email));if(this.auditUser)emails.push(this.auditUser);const emailParam=emails.length?emails.join(','):null;const fromParam=this.auditFrom?new Date(this.auditFrom).toISOString():null;const toParam=this.auditTo?new Date(this.auditTo+'T23:59:59').toISOString():null;const{data,error}=await this.supabase.rpc('admin_get_audit_trail',{p_table_name:this.auditFilter||null,p_user_email:emailParam,p_limit:AUDIT_PER_PAGE,p_offset:off,p_from:fromParam,p_to:toParam});if(error)throw error;this.auditLogs=data?.records||[];this.auditTotal=data?.total||0}catch(e){console.warn('audit error:',e.message);this.showToast('Nie udało się załadować audytu','error')}this.auditLoading=false},
    toggleAuditUser(u){const i=this.auditSelectedUsers.findIndex(s=>s.id===u.id);if(i>-1)this.auditSelectedUsers.splice(i,1);else this.auditSelectedUsers.push(u);this.loadAudit(true)},
    debounceAudit(){if(this._debounceTimer)clearTimeout(this._debounceTimer);this._debounceTimer=setTimeout(()=>this.loadAudit(true),400)},
    async loadTempGrants(){try{const{data,error}=await this.supabase.rpc('admin_get_temporary_grants');if(error)throw error;this.tempGrants=data||[]}catch(e){console.warn('loadTempGrants error:',e.message);this.showToast('Nie udało się załadować tymczasowych dostępów','error')}},
    async loadRoles(){try{const{data,error}=await this.supabase.rpc('admin_get_roles_with_templates');if(error)throw error;this.processRolesData(data)}catch(e){console.warn('loadRoles error:',e.message);this.showToast('Nie udało się załadować ról','error')}},
    async afterMutation(o={}){const p=[];if(o.users)p.push(this.refreshUsers());if(o.roles)p.push(this.loadRoles());if(o.stats)p.push(this.refreshStats());if(o.temp)p.push(this.loadTempGrants());if(this.activePage==='audit')p.push(this.loadAudit());await Promise.allSettled(p);if(o.userId&&this.selectedUser)this.selectedUser=this.users.find(u=>u.id===o.userId)||null},
    openDetail(u){this.activeModal=null;this.selectedUser=u;this.detailTab='roles'},
    async addRole(uid,rn){if(this.actionLoading)return;this.actionLoading='addRole';try{const{error}=await this.supabase.rpc('admin_assign_role',{p_user_id:uid,p_role_name:rn});if(error)throw error;this.showToast(`Rola ${rn} przypisana`,'success');this.activeModal=null;await this.afterMutation({users:true,roles:true,userId:uid})}catch(e){console.warn('addRole error:',e.message);this.showToast('Nie udało się przypisać roli','error')}finally{this.actionLoading=null}},
    async removeRoleConfirmed(uid,rn){try{const tg=this.tempGrants.find(g=>g.grant_type==='role'&&g.role_name===rn&&g.user_id===uid);if(tg){await this.supabase.rpc('admin_revoke_temp_grant',{p_grant_id:tg.id})}const{error}=await this.supabase.rpc('admin_remove_role',{p_user_id:uid,p_role_name:rn});if(error)throw error;this.showToast(`Rola ${rn} usunięta`,'success');await this.afterMutation({users:true,roles:true,temp:true,userId:uid})}catch(e){console.warn('removeRole error:',e.message);this.showToast('Nie udało się usunąć roli','error')}},
    async createRole(){if(this.actionLoading)return;this.actionLoading='createRole';try{const name=this.newRoleName.trim();if(!name)return;if(name.length>50){this.showToast('Nazwa roli za długa (maks. 50 znaków)','error');return}if(!/^[a-zA-Zа-яА-ЯёЁąćęłńóśźżĄĆĘŁŃÓŚŹŻ0-9_\- ]+$/.test(name)){this.showToast('Nazwa roli zawiera niedozwolone znaki','error');return}const t=this.newRoleTemplates.filter(t=>t.table_name&&t.actions.length).map(t=>({table_name:t.table_name,actions:t.actions}));const{error}=await this.supabase.rpc('admin_create_role',{p_role_name:name,p_templates:t,p_color_bg:this.newRoleColorBg||null,p_color_fg:this.newRoleColorFg||null});if(error)throw error;this.showToast('Rola utworzona','success');this.activeModal=null;this.newRoleName='';this.newRoleTemplates=[];await this.afterMutation({roles:true,stats:true})}catch(e){console.warn('createRole error:',e.message);this.showToast('Nie udało się utworzyć roli','error')}finally{this.actionLoading=null}},
    async deleteRoleConfirmed(rn){try{const{data,error}=await this.supabase.rpc('admin_delete_role',{p_role_name:rn,p_force:true});if(error)throw error;if(data?.success===false){this.showToast(data.error,'error');return}this.showToast('Rola usunięta','success');await this.afterMutation({roles:true,users:true,stats:true})}catch(e){console.warn('deleteRole error:',e.message);this.showToast('Nie udało się usunąć roli','error')}},
    openEditRole(rl){this.editRoleName=rl.name;this.editRoleColorBg=rl.color_bg||this.roleColorsMap[rl.name]?.bg||ROLE_COLORS[rl.name]?.bg||'#333';this.editRoleColorFg=rl.color_fg||this.roleColorsMap[rl.name]?.fg||ROLE_COLORS[rl.name]?.fg||'#ccc';this.editRoleTemplates=(rl.templates||[]).map(t=>({table_name:t.table_name,actions:[...(t.actions||[])].filter(a=>a!=='all')}));this.openModal('editRole')},
    async saveRoleTemplates(){try{const t=this.editRoleTemplates.filter(t=>t.table_name&&t.actions.length).map(t=>({table_name:t.table_name,actions:t.actions}));const{error}=await this.supabase.rpc('admin_update_role_templates',{p_role_name:this.editRoleName,p_templates:t});if(error)throw error;await this.supabase.rpc('admin_update_role_color',{p_role_name:this.editRoleName,p_color_bg:this.editRoleColorBg,p_color_fg:this.editRoleColorFg});this.showToast('Rola zaktualizowana','success');this.activeModal=null;await this.afterMutation({roles:true,users:true})}catch(e){console.warn('saveRoleTemplates error:',e.message);this.showToast('Nie udało się zaktualizować roli','error')}},
    openEditPermissions(){if(!this.selectedUser)return;const p=this.selectedUser.permissions||{};this.editPermsData=Object.entries(p).map(([t,a])=>({table_name:t,actions:Array.isArray(a)?[...a]:[a]}));if(!this.editPermsData.length)this.editPermsData.push({table_name:'',actions:[]});this.openModal('editPerms')},
    async saveUserPermissions(){try{const o={};for(const p of this.editPermsData){if(p.table_name&&p.actions.length)o[p.table_name]=p.actions}const{error}=await this.supabase.rpc('admin_update_user_permissions',{p_user_id:this.selectedUser.id,p_permissions:o});if(error)throw error;this.showToast('Uprawnienia zaktualizowane','success');this.activeModal=null;await this.afterMutation({users:true,userId:this.selectedUser.id})}catch(e){console.warn('savePerms error:',e.message);this.showToast('Nie udało się zaktualizować uprawnień','error')}},
    closeCopyModal(){this.activeModal=null;this.copyStep=1;this.copySearch='';this.copyTarget=null;this.copyRoles=[];this.copyOdz=[]},
    selectCopyTarget(u){this.copyTarget=u;this.copyRoles=[...(u.roles||[])];const s=u.allowed_oddzial_ids;this.copyOdz=(s===null||s===undefined)?this.allOdz.map(o=>o.id):[...(Array.isArray(s)?s:[])];this.sourceOdz=[...this.copyOdz];this.copyStep=2},
    toggleCopyRole(r){const i=this.copyRoles.indexOf(r);i>-1?this.copyRoles.splice(i,1):this.copyRoles.push(r)},
    toggleCopyOdz(id){const i=this.copyOdz.indexOf(id);i>-1?this.copyOdz.splice(i,1):this.copyOdz.push(id)},
    async applyCopy(){if(this.actionLoading)return;this.actionLoading='applyCopy';try{const p={p_from_user_id:this.copyTarget.id,p_to_user_id:this.selectedUser.id,p_copy_roles:true,p_copy_oddzialy:!this.copyOdzChanged};if(this.copyAdded.length)p.p_add_roles=this.copyAdded;if(this.copyRemoved.length)p.p_remove_roles=this.copyRemoved;if(this.copyOdzChanged)p.p_override_oddzialy=this.copyOdz;const{error}=await this.supabase.rpc('admin_copy_permissions',p);if(error)throw error;this.showToast('Uprawnienia skopiowane','success');const uid=this.selectedUser.id;this.closeCopyModal();await this.afterMutation({users:true,roles:true,stats:true,userId:uid})}catch(e){console.warn('applyCopy error:',e.message);this.showToast('Nie udało się skopiować uprawnień','error')}finally{this.actionLoading=null}},
    toggleTempOdz(id){const i=this.tempGrantOdz.indexOf(id);i>-1?this.tempGrantOdz.splice(i,1):this.tempGrantOdz.push(id)},
    _validateFutureDate(val,maxYears=1){const d=new Date(val);if(isNaN(d.getTime())){this.showToast('Podaj prawidłową datę','error');return null}if(d<=new Date()){this.showToast('Data musi być w przyszłości','error');return null}const max=new Date();max.setFullYear(max.getFullYear()+maxYears);if(d>max){this.showToast(`Maksymalny okres — ${maxYears} rok`,'error');return null}return d.toISOString()},
    async applyTempGrant(){if(this.actionLoading)return;this.actionLoading='applyTempGrant';try{const exp=this._validateFutureDate(this.tempGrantExp);if(!exp){this.actionLoading=null;return}let error;if(this.tempGrantType==='role'){({error}=await this.supabase.rpc('admin_grant_temporary_role',{p_user_id:this.selectedUser.id,p_role_name:this.tempGrantRole,p_expires_at:exp,p_reason:this.tempGrantReason||null}))}else{({error}=await this.supabase.rpc('admin_grant_temporary_oddzial',{p_user_id:this.selectedUser.id,p_oddzial_ids:this.tempGrantOdz,p_expires_at:exp,p_reason:this.tempGrantReason||null}))}if(error)throw error;this.showToast('Tymczasowy dostęp nadany','success');this.activeModal=null;this.tempGrantRole='';this.tempGrantOdz=[];this.tempGrantExp='';this.tempGrantReason='';await this.afterMutation({users:true,temp:true,stats:true,userId:this.selectedUser?.id})}catch(e){console.warn('applyTempGrant error:',e.message);this.showToast('Nie udało się nadać tymczasowego dostępu','error')}finally{this.actionLoading=null}},
    extendGrant(g){this.extendGrant_=g;this.extendDate='';this.extendReason='';this.openModal('extend')},
    async doExtend(){try{const newExp=this._validateFutureDate(this.extendDate);if(!newExp)return;const{error}=await this.supabase.rpc('admin_extend_temp_grant',{p_grant_id:this.extendGrant_.id,p_new_expires_at:newExp,p_reason:this.extendReason||null});if(error)throw error;this.showToast('Przedłużono','success');this.activeModal=null;await this.afterMutation({temp:true})}catch(e){console.warn('doExtend error:',e.message);this.showToast('Nie udało się przedłużyć dostępu','error')}},
    async revokeGrantConfirmed(g){try{const{error}=await this.supabase.rpc('admin_revoke_temp_grant',{p_grant_id:g.id});if(error)throw error;this.showToast('Cofnięto','success');await this.afterMutation({temp:true,users:true,userId:this.selectedUser?.id})}catch(e){console.warn('revokeGrant error:',e.message);this.showToast('Nie udało się cofnąć dostępu','error')}},
    async addDept(uid,deptId,deptName){try{const ids=this.selectedUser?.allowed_oddzial_ids;const current=Array.isArray(ids)?[...ids]:[];if(!current.includes(deptId))current.push(deptId);const{error}=await this.supabase.rpc('admin_set_user_oddzialy',{p_user_id:uid,p_oddzial_ids:current});if(error)throw error;this.showToast(`Oddział ${deptName} dodany`,'success');await this.afterMutation({users:true,userId:uid})}catch(e){console.warn('addDept error:',e.message);this.showToast('Nie udało się dodać oddziału','error')}},
    async removeDeptConfirmed(uid,deptId,deptName){try{const tg=this.tempGrants.find(g=>g.grant_type==='oddzial'&&g.oddzial_id===deptId&&g.user_id===uid);if(tg){await this.supabase.rpc('admin_revoke_temp_grant',{p_grant_id:tg.id})}const ids=this.selectedUser?.allowed_oddzial_ids;const current=Array.isArray(ids)?ids.filter(id=>id!==deptId):[];const{error}=await this.supabase.rpc('admin_set_user_oddzialy',{p_user_id:uid,p_oddzial_ids:current});if(error)throw error;this.showToast(`Oddział ${deptName} usunięty`,'success');await this.afterMutation({users:true,temp:true,userId:uid})}catch(e){console.warn('removeDept error:',e.message);this.showToast('Nie udało się usunąć oddziału','error')}},
    confirmAction(action,payload){const c=this.content;const titles={deleteRole:c.labelConfirmDeleteRoleTitle||'Usunięcie roli',removeRole:c.labelConfirmRemoveRoleTitle||'Usunięcie roli użytkownikowi',revokeGrant:c.labelConfirmRevokeTitle||'Cofnięcie tymczasowego dostępu',removeDept:'Usunięcie dostępu do oddziału'};const msgs={deleteRole:(c.labelConfirmDeleteRole||'Usunąć rolę "{role}"? To usunie ją od wszystkich użytkowników.').replace('{role}',payload),removeRole:(c.labelConfirmRemoveRole||'Usunąć rolę "{role}" użytkownikowi {user}?').replace('{role}',payload.role).replace('{user}',this.selectedUser?.full_name||''),revokeGrant:c.labelConfirmRevoke||'Cofnąć tymczasowy dostęp?',removeDept:`Usunąć dostęp do oddziału "${payload.deptName}" użytkownikowi ${this.selectedUser?.full_name||''}?`};this.confirmModal={action,payload,title:titles[action]||'Potwierdzenie',message:msgs[action]||'Czy na pewno?'}},
    executeConfirmed(){if(!this.confirmModal)return;const{action,payload}=this.confirmModal;this.confirmModal=null;if(action==='deleteRole')this.deleteRoleConfirmed(payload);else if(action==='removeRole')this.removeRoleConfirmed(payload.uid,payload.role);else if(action==='revokeGrant')this.revokeGrantConfirmed(payload);else if(action==='removeDept')this.removeDeptConfirmed(payload.uid,payload.deptId,payload.deptName)},
    isTempRole(u,rn){return this.tempGrants.some(g=>g.grant_type==='role'&&g.role_name===rn&&g.user_id===u.id)},
    tempRoleTooltip(u,rn){const g=this.tempGrants.find(g=>g.grant_type==='role'&&g.role_name===rn&&g.user_id===u.id);return g?`Tymczasowa do: ${this.formatDate(g.expires_at)} (${this.formatTimeRemaining(g.time_remaining)})`:''}, 
    isTempDept(u,did){return this.tempGrants.some(g=>g.grant_type==='oddzial'&&g.oddzial_id===did&&g.user_id===u.id)},
    tempDeptTooltip(u,did){const g=this.tempGrants.find(g=>g.grant_type==='oddzial'&&g.oddzial_id===did&&g.user_id===u.id);return g?`Tymczasowy do: ${this.formatDate(g.expires_at)} (${this.formatTimeRemaining(g.time_remaining)})`:''},
    tempRoleTime(u,rn){const g=this.tempGrants.find(g=>g.grant_type==='role'&&g.role_name===rn&&g.user_id===u.id);return g?this.formatTimeRemaining(g.time_remaining):''},
    isTempRoleUrgent(u,rn){const g=this.tempGrants.find(g=>g.grant_type==='role'&&g.role_name===rn&&g.user_id===u.id);return g?this.isUrgent(g.expires_at):false},
    userHasAllDepts(u){if(!u)return false;const ids=u.allowed_oddzial_ids;return ids===null||ids===undefined},
    userHasDept(u,did){if(!u)return false;const ids=u.allowed_oddzial_ids;if(ids===null||ids===undefined)return true;if(Array.isArray(ids)&&ids.includes(did))return true;return this.isTempDept(u,did)},
    countUserDepts(u){if(!u)return 0;const ids=u.allowed_oddzial_ids;if(ids===null||ids===undefined)return this.allOdz.length;let c=Array.isArray(ids)?ids.length:0;this.allOdz.forEach(o=>{if(!(ids||[]).includes(o.id)&&this.isTempDept(u,o.id))c++});return c},
    userDeptCount(u){return this.countUserDepts(u)},
    userDeptNames(u){if(!u)return[];const ids=u.allowed_oddzial_ids;const isAll=ids===null||ids===undefined;return this.allOdz.filter(o=>isAll||(Array.isArray(ids)&&ids.includes(o.id))||this.isTempDept(u,o.id)).map(o=>{const temp=!isAll&&!(Array.isArray(ids)&&ids.includes(o.id))&&this.isTempDept(u,o.id);const g=temp?this.tempGrants.find(g=>g.grant_type==='oddzial'&&g.oddzial_id===o.id&&g.user_id===u.id):null;return{name:o.name,isTemp:temp,tooltip:this.tempDeptTooltip(u,o.id),timeLeft:g?this.formatTimeRemaining(g.time_remaining):'',urgent:g?this.isUrgent(g.expires_at):false}})},
    toggleAction(t,a){const i=t.actions.indexOf(a);i>-1?t.actions.splice(i,1):t.actions.push(a)},
    hasAllActions(t){return['select','insert','update','delete'].every(a=>t.actions.includes(a))},
    toggleAllActions(t){t.actions=this.hasAllActions(t)?[]:['select','insert','update','delete']},
    roleBadgeStyle(role){const db=this.roleColorsMap[role?.toLowerCase()]||this.roleColorsMap[role];if(db)return{backgroundColor:db.bg,color:db.fg};const c=ROLE_COLORS[role?.toLowerCase()]||{bg:'#333',fg:'#ccc'};return{backgroundColor:c.bg,color:c.fg}},
    statusLabel(s){return{active:this.L('labelStatusActive'),inactive:this.L('labelStatusInactive'),terminated:this.L('labelStatusTerminated'),vacation:this.L('labelStatusVacation')}[s]||s||'—'},
    initials(n){return(n||'').split(' ').map(w=>w[0]).join('').substring(0,2)},
    truncate(s,n){return s&&s.length>n?s.substring(0,n)+'…':s},
    formatDate(d){return d?new Date(d).toLocaleString('pl-PL'):''},
    formatTimeRemaining(v){if(!v)return'—';const s=String(v);const m1=s.match(/(\d+)\s*days?\s*(\d+):(\d+)/);if(m1)return`${m1[1]}d ${m1[2]}h ${m1[3]}m`;const m2=s.match(/(\d+):(\d+):(\d+)/);if(m2)return`${m2[1]}h ${m2[2]}m`;return s},
    isUrgent(e){return e&&(new Date(e)-new Date()<3600000)},
    showToast(msg,type='info'){const id=++this._toastCounter;this.toasts.push({id,message:msg,type});const delay=type==='success'?3500:8000;const tid=setTimeout(()=>this.dismissToast(id),delay);if(!this._toastTimers)this._toastTimers=[];this._toastTimers.push(tid)},
    dismissToast(id){const i=this.toasts.findIndex(t=>t.id===id);if(i>-1)this.toasts.splice(i,1)},
    async resolveIcon(key,val){if(!val){this.$set?this.$set(this.resolvedIcons,key,''):this.resolvedIcons[key]='';return}try{if(typeof wwLib!=='undefined'&&wwLib.useIcons){const{getIcon}=wwLib.useIcons();const svg=await getIcon(val);const v=svg||'';this.$set?this.$set(this.resolvedIcons,key,v):this.resolvedIcons[key]=v}else{const s=String(val).replace(/\//g,':');const v=`<img src="https://api.iconify.design/${s}.svg" style="width:100%;height:100%;object-fit:contain"/>`;this.$set?this.$set(this.resolvedIcons,key,v):this.resolvedIcons[key]=v}}catch(e){this.$set?this.$set(this.resolvedIcons,key,''):this.resolvedIcons[key]=''}},
    resolveAllIcons(){const keys=['iconNavDashboard','iconNavUsers','iconNavRoles','iconNavAudit','iconNavTemp','iconNavMatrix','iconNavRequests','iconSetup','iconTempIndicator','iconClose','iconEdit','iconDelete','iconCheckmark'];keys.forEach(k=>{this.resolveIcon(k,this.content[k])})},
    getIconHtml(key){if(this.resolvedIcons[key])return this.resolvedIcons[key];const val=this.content[key];if(!val)return'';const s=String(val).replace(/\//g,':');if(!/^[a-zA-Z0-9:\-]+$/.test(s))return'';return`<img src="https://api.iconify.design/${s}.svg" style="width:100%;height:100%;object-fit:contain"/>`},
    initChartDates(){const to=new Date();const from=new Date();from.setDate(from.getDate()-30);this.chartTo=to.toISOString().slice(0,10);this.chartFrom=from.toISOString().slice(0,10)},
    async loadChart(){if(!this.supabase)return;this.chartLoading=true;try{const{data,error}=await this.supabase.rpc('admin_get_clients_chart',{p_from:this.chartFrom,p_to:this.chartTo});if(error)throw error;this.chartData=data||[]}catch(e){console.warn('chart loading failed:',e.message)}this.chartLoading=false},
    async loadDeptStats(){if(!this.supabase)return;try{const{data,error}=await this.supabase.rpc('admin_get_dept_stats_with_diff',{p_days:30});if(error)throw error;this.deptStats=data||[]}catch(e){console.warn('deptStats loading failed:',e.message)}},
    chartPath(){const d=this.chartData;if(!d.length)return'';const counts=d.map(p=>p.count);const maxV=Math.max(...counts,1);const minV=Math.min(...counts,0);const range=maxV-minV||1;const w=600;const h=180;const padT=10;const padB=10;const usableH=h-padT-padB;const step=d.length>1?w/(d.length-1):0;return d.map((p,i)=>{const x=d.length>1?i*step:w/2;const y=padT+usableH-(((p.count-minV)/range)*usableH);return(i===0?'M':'L')+x.toFixed(1)+','+y.toFixed(1)}).join(' ')},
    chartAreaPath(){const line=this.chartPath();if(!line)return'';const d=this.chartData;const w=600;const h=180;const lastX=d.length>1?(d.length-1)*(w/(d.length-1)):w/2;return line+' L'+lastX+','+h+' L0,'+h+' Z'},
    chartPoints(){const d=this.chartData;if(!d.length)return[];const counts=d.map(p=>p.count);const maxV=Math.max(...counts,1);const minV=Math.min(...counts,0);const range=maxV-minV||1;const w=600;const h=180;const padT=10;const padB=10;const usableH=h-padT-padB;const step=d.length>1?w/(d.length-1):0;return d.map((p,i)=>({x:d.length>1?i*step:w/2,y:padT+usableH-(((p.count-minV)/range)*usableH),count:p.count,day:p.day}))},
    chartYLabels(){const d=this.chartData;if(!d.length)return[];const counts=d.map(p=>p.count);const maxV=Math.max(...counts,1);const minV=Math.min(...counts,0);const range=maxV-minV||1;const steps=4;const labels=[];for(let i=0;i<=steps;i++){const v=Math.round(minV+(range*(i/steps)));labels.push({v,y:10+(180-10-10)-(((v-minV)/range)*(180-10-10))})}return labels},
    chartXLabels(){const d=this.chartData;if(!d.length)return[];const w=600;const step=d.length>1?w/(d.length-1):0;const skip=Math.max(1,Math.floor(d.length/8));return d.filter((_,i)=>i%skip===0||i===d.length-1).map(p=>{const i=d.indexOf(p);return{x:d.length>1?i*step:w/2,label:p.day?p.day.slice(5).replace('-','/'):''} })},
    showChartTip(e,p){const rect=this.$refs.chartContainer?.getBoundingClientRect();if(!rect)return;const x=e.clientX-rect.left;const y=e.clientY-rect.top;const rightAlign=x>rect.width*0.75;this.chartTipPos={x,y,rightAlign,containerW:rect.width};this.chartHover=p},
    setAuditDatePreset(p){const now=new Date();this.auditTo=now.toISOString().slice(0,10);if(p==='today')this.auditFrom=this.auditTo;else if(p==='7d'){const d=new Date();d.setDate(d.getDate()-7);this.auditFrom=d.toISOString().slice(0,10)}else if(p==='30d'){const d=new Date();d.setDate(d.getDate()-30);this.auditFrom=d.toISOString().slice(0,10)}this.loadAudit(true)},
    exportCSV(type){let rows=[];let filename='export.csv';if(type==='users'){filename='users.csv';rows=[['Imię','Email','Oddział','Role','Status','Klientów']];this.sortedFilteredUsers.forEach(u=>rows.push([u.full_name,u.email,u.oddzial||'',(u.roles||[]).join('; '),u.status||'',u.visible_clients_count||0]))}else if(type==='audit'){filename='audit.csv';rows=[['Data','Tabela','Akcja','Email','Opis','Szczegóły']];this.auditLogs.forEach(a=>rows.push([a.created_at,a.table_name,a.action_type||'',a.user_email||'',a.human_description||a.description||'',a.details||'']))}else if(type==='roles'){filename='roles.csv';rows=[['Rola','Użytkowników','Szablony']];this.rolesWithTemplates.forEach(r=>rows.push([r.name,r.users_count||0,(r.templates||[]).map(t=>t.table_name+':'+t.actions.join('+')).join('; ')]))}else if(type==='temp'){filename='temp_grants.csv';rows=[['Użytkownik','Typ','Rola/Oddział','Wygasa','Nadane przez','Powód']];this.tempGrants.forEach(g=>rows.push([g.user_name,g.grant_type,g.grant_type==='role'?g.role_name:g.oddzial_name,g.expires_at,g.created_by||'',g.reason||'']))}const csv=rows.map(r=>r.map(c=>'"'+String(c).replace(/"/g,'""')+'"').join(',')).join('\n');const blob=new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8;'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=filename;a.click();URL.revokeObjectURL(url)},
    toggleBulkUser(uid){const i=this.selectedUserIds.indexOf(uid);i>-1?this.selectedUserIds.splice(i,1):this.selectedUserIds.push(uid)},
    toggleBulkAll(){if(this.selectedUserIds.length===this.paginatedUsers.length){this.selectedUserIds=[]}else{this.selectedUserIds=this.paginatedUsers.map(u=>u.id)}},
    async bulkAssignRole(roleName){if(this.actionLoading||!this.selectedUserIds.length)return;this.actionLoading='bulk';try{const{error}=await this.supabase.rpc('admin_bulk_assign_role',{p_user_ids:this.selectedUserIds,p_role_name:roleName});if(error)throw error;this.showToast(`Rola ${roleName} przypisana ${this.selectedUserIds.length} użytkownikom`,'success');this.selectedUserIds=[];this.activeModal=null;await this.afterMutation({users:true,roles:true,stats:true})}catch(e){console.warn('bulkAssignRole error:',e.message);this.showToast('Nie udało się przypisać roli grupowo','error')}finally{this.actionLoading=null}},
    async bulkAddDept(deptId,deptName){if(this.actionLoading||!this.selectedUserIds.length)return;this.actionLoading='bulk';try{const{error}=await this.supabase.rpc('admin_bulk_add_oddzial',{p_user_ids:this.selectedUserIds,p_oddzial_id:deptId});if(error)throw error;this.showToast(`Oddział ${deptName} dodany ${this.selectedUserIds.length} użytkownikom`,'success');this.selectedUserIds=[];this.activeModal=null;await this.afterMutation({users:true,stats:true})}catch(e){console.warn('bulkAddDept error:',e.message);this.showToast('Nie udało się dodać oddziału grupowo','error')}finally{this.actionLoading=null}},
    async loadUserHistory(){if(!this.selectedUser)return;this.userHistoryLoading=true;this.historyPage=1;try{const{data,error}=await this.supabase.rpc('admin_get_user_history',{p_user_id:this.selectedUser.id,p_limit:200});if(error)throw error;this.userHistory=data||[]}catch(e){console.warn('loadUserHistory error:',e.message);this.userHistory=[]}this.userHistoryLoading=false},
    contrastRatio(hex1,hex2){const lum=h=>{const r=parseInt(h.slice(1,3),16)/255;const g=parseInt(h.slice(3,5),16)/255;const b=parseInt(h.slice(5,7),16)/255;const f=c=>c<=0.03928?c/12.92:Math.pow((c+0.055)/1.055,2.4);return 0.2126*f(r)+0.7152*f(g)+0.0722*f(b)};const l1=lum(hex1);const l2=lum(hex2);const lighter=Math.max(l1,l2);const darker=Math.min(l1,l2);return(lighter+0.05)/(darker+0.05)},
    contrastWarning(bg,fg){if(!bg||!fg||bg.length!==7||fg.length!==7)return'';const r=this.contrastRatio(bg,fg);if(r<2)return'Bardzo niski kontrast ('+r.toFixed(1)+':1) — tekst nieczytelny';if(r<3)return'Niski kontrast ('+r.toFixed(1)+':1) — może być trudny do odczytania';return''},
    async loadRequests(){this.requestsLoading=true;try{if(this.isAdmin){const{data,error}=await this.supabase.rpc('admin_get_pending_requests');if(!error)this.accessRequests=data||[]}const{data:myData,error:myErr}=await this.supabase.rpc('get_my_access_requests');if(!myErr)this.myRequests=myData||[]}catch(e){console.warn('loadRequests error:',e.message)}this.requestsLoading=false},
    resetRequestForm(){this.newRequestTarget='';this.newRequestRoles=[];this.newRequestDepts=[];this.newRequestReason=''},
    toggleRequestRole(r){const i=this.newRequestRoles.indexOf(r);i>-1?this.newRequestRoles.splice(i,1):this.newRequestRoles.push(r)},
    toggleRequestDept(id){const i=this.newRequestDepts.indexOf(id);i>-1?this.newRequestDepts.splice(i,1):this.newRequestDepts.push(id)},
    async submitAccessRequest(){if(this.actionLoading)return;this.actionLoading='submitRequest';try{const items=[];this.newRequestRoles.forEach(r=>items.push({type:'role',role_name:r,oddzial_id:null}));this.newRequestDepts.forEach(id=>items.push({type:'oddzial',role_name:null,oddzial_id:id}));if(!items.length){this.showToast('Wybierz przynajmniej jedną rolę lub oddział','error');this.actionLoading=null;return}for(const item of items){const{error}=await this.supabase.rpc('create_access_request',{p_target_user_id:this.newRequestTarget,p_request_type:item.type,p_role_name:item.role_name,p_oddzial_id:item.oddzial_id,p_reason:this.newRequestReason||null});if(error)throw error}this.showToast(`Wysłano ${items.length} wniosków`,'success');this.resetRequestForm();await this.loadRequests()}catch(e){console.warn('submitRequest error:',e.message);this.showToast('Nie udało się wysłać wniosku','error')}finally{this.actionLoading=null}},
    async reviewRequest(reqId,action){if(this.actionLoading)return;this.actionLoading='review';try{const{error}=await this.supabase.rpc('admin_review_access_request',{p_request_id:reqId,p_action:action,p_comment:this.reviewComment||null});if(error)throw error;this.showToast(action==='approved'?'Wniosek zaakceptowany':'Wniosek odrzucony','success');this.reviewComment='';await this.loadRequests();if(action==='approved')await this.afterMutation({users:true,roles:true,stats:true})}catch(e){console.warn('reviewRequest error:',e.message);this.showToast('Nie udało się przetworzyć wniosku','error')}finally{this.actionLoading=null}},
    diffClass(d){if(d>0)return'diff-positive';if(d<0)return'diff-negative';return'diff-neutral'},
    diffText(d){if(d>0)return'+'+d;if(d<0)return''+d;return'0'},
  },
};
</script>

<style scoped>
.admin-panel{font-family:var(--font);color:var(--text);background:var(--bg);min-height:100vh;font-size:var(--body-size)}
